Rule.Source:
        
        import java.util.List;
        import sailpoint.object.Certification;
        import sailpoint.object.CertificationEntity;
        import sailpoint.object.CertificationItem;
        import sailpoint.object.EntitlementSnapshot;
        import sailpoint.object.Identity;

        String logName = "Ascension.Rule.Ascension-Rule-Certification-SystemAdministratorManager-ActivePhase";
        debug(logName,"Enter rule Ascension-Rule-Certification-SystemAdministratorManager-ActivePhase");
        if (certification != null) {
            try {
                List entities = certification.getEntities();
                for (CertificationEntity entity : entities) {
                    String idStr = entity.getIdentity();
                    Identity iden = context.getObjectByName(Identity.class, idStr);
                    String managerName = "Undefined";
                    if(iden != null && iden.getManager() != null){
                        managerName = iden.getManager().getDisplayName();
                    }
                    List certItems = entity.getItems();
                    for (CertificationItem item : certItems) {
                        EntitlementSnapshot entitlementSnapshot = item.getExceptionEntitlements();                                                                      
                        if (entitlementSnapshot != null ) {
                            entitlementSnapshot.setDisplayName("Manager: "+managerName) ;
                            //Update the value the UI uses for the Account Name column of line items within an Access Review
                        }
                    }
                }
            }catch(Exception e) {
                error(logName,"Error while executing the rule Ascension-Rule-Certification-SystemAdministratorManager-ActivePhase",e);
            }
        }
        debug(logName,"Exit rule Ascension-Rule-Certification-SystemAdministratorManager-ActivePhase");
